class Solution {
    class TrieNode {
        TrieNode[] children = new TrieNode[2];
    }
    private TrieNode root;
    private void insert(int num) {
        TrieNode node = root;
        for (int i = 31; i >= 0; i--) {
            int bit = (num >> i) & 1;
            if (node.children[bit] == null) {
                node.children[bit] = new TrieNode();
            }
            node = node.children[bit];
        }
    }
    private int findMaxXor(int num) {
        TrieNode node = root;
        int maxXor = 0;
        for (int i = 31; i >= 0; i--) {
            int bit = (num >> i) & 1;
            int oppositeBit = bit ^ 1;
            if (node.children[oppositeBit] != null) {
                maxXor |= (1 << i);
                node = node.children[oppositeBit];
            }
            else {
                node = node.children[bit];
            }
        }
        return maxXor;
    }
    public int maximumXorOfTwoNumbersInAnArray(int[] data) {
        root = new TrieNode();
        for (int num : data) {
            insert(num);
        }
        int maxResult = 0;
        for (int num : data) {
            maxResult = Math.max(maxResult, findMaxXor(num));
        }
        return maxResult;
    }
}

