func (t *Trie) insert(num int) {
    node := t.root
    for i := 31; i >= 0; i-- {
        bit := (num >> i) & 1
        if node.children[bit] == nil {
            node.children[bit] = &TrieNode{}
        }
        node = node.children[bit]
    }
}

func (t *Trie) maxXor(num int) int {
    node := t.root
    maxXor := 0
    for i := 31; i >= 0; i-- {
        bit := (num >> i) & 1
        toggleBit := 1 - bit
        if node.children[toggleBit] != nil {
            maxXor |= (1 << i)
            node = node.children[toggleBit]
        } else {
            node = node.children[bit]
        }
    }
    return maxXor
}

func maximumXorOfTwoNumbersInAnArray(data []int) int {
    trie := &Trie{root: &TrieNode{}}
    maxXor := 0

    for _, num := range data {
        trie.insert(num)
    }

    for _, num := range data {
        currentXor := trie.maxXor(num)
        if currentXor > maxXor {
            maxXor = currentXor
        }
    }

    return maxXor
}

